  ('dietitian-moex-07111', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關血糖調控的敘述，下列何者錯誤？ 胰島素（insulin）抑制脂肪分解，並使血糖下降 腎上腺皮質類固醇（adrenal corticosteroids）促進消化道對葡萄糖的吸收，使血糖上升 昇糖激素（glucagon）促進肝臟內肝醣分解，使血糖上升 ACTH（adrenocorticotropic hormone）減少組織對葡萄糖的利用，使血糖上升', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
