  ('dietitian-moex-07113', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關糖尿病團隊共同照護的敘述，下列何者錯誤？ 團隊成員通常被要求通過糖尿病衛教師認證，醫師也不例外 通過糖尿病衛教師認證的營養師，代表他們具有糖尿病方面的專業知識，於教導糖尿病病人上具有專 業優勢 團隊共同照護的目的是提供糖尿病人相關「知識」，但不包括「技能」方面的訓練 糖尿病人本身也有將「自我管理」行動納入每日生活作息中之義務', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "73db2979bfee", "answer_pdf_sha1": "152727bd9506", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
